package org.apache.commons.csv;

import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import static org.junit.jupiter.api.Assertions.assertEquals;

public class CSVFormatTest {

    @Test
    public void testGetCommentMarker() throws NoSuchFieldException, IllegalAccessException {
        // Given
        CSVFormat csvFormat = new CSVFormat(',', '\"', null, '#', '\\', true, false, "\r\n", null, null, false, true);

        // When
        Character commentMarker = csvFormat.getCommentMarker();

        // Then
        assertEquals('#', commentMarker);
    }
}
